    RemoveStatus(checker::CheckerStatus::IN_INSTANCEOF_CONTEXT);

    return {GlobalETSBooleanBuiltinType(),
            exprValidity == BinaryExpressionValidity::NO_ERR ? GlobalETSObjectType() : leftType};
}

